{
    "@type": "JobPosting",
    "image": "https://media.licdn.com/dms/image/v2/C4E0BAQEpBGJGx1uIMg/company-logo_100_100/company-logo_100_100/0/1658499185302/integrichain_logo?e=2147483647&v=beta&t=baZ3CJIZ2_jgkBQ0--61cjjsqmCl3K5CoT6DLZ4SZ-4",
    "title": "Executive Administrative Assistant",
    "skills": "",
    "@context": "http://schema.org",
    "industry": "Software Development",
    "datePosted": "2024-09-28T09:56:25.000Z",
    "identifier": {
